  1→import { CommonModule } from '@angular/common';
  2→import {
  3→    ChangeDetectionStrategy,
  4→    Component,
  5→    computed,
  6→    inject,
  7→    Input,
  8→    input,
  9→    OnDestroy,
 10→    OnInit,
 11→    signal,
 12→} from '@angular/core';
 13→import { toSignal } from '@angular/core/rxjs-interop';
 14→import { MatButtonModule } from '@angular/material/button';
 15→import { MatIconModule } from '@angular/material/icon';
 16→import { ActivatedRoute, NavigationEnd, Router } from '@angular/router';
 17→import { Store } from '@ngrx/store';
 18→import { StorageMap } from '@ngx-pwa/local-storage';
 19→import { TranslatePipe } from '@ngx-translate/core';
 20→import { EpgService } from '@iptvnator/epg/data-access';
 21→import {
 22→    isWorkspaceLayoutRoute,
 23→    queryParamSignal,
 24→} from '@iptvnator/portal/shared/util';
 25→import {
 26→    ChannelActions,
 27→    FavoritesActions,
 28→    PlaylistActions,
 29→    selectActive,
 30→    selectActivePlaylistId,
 31→    selectFavorites,
 32→} from 'm3u-state';
 33→import {
 34→    BehaviorSubject,
 35→    combineLatest,
 36→    filter,
 37→    firstValueFrom,
 38→    map,
 39→    skipWhile,
 40→} from 'rxjs';
 41→import { PlaylistsService } from 'services';
 42→import {
 43→    Channel,
 44→    EpgProgram,
 45→    isM3uRecentlyViewedItem,
 46→    normalizeStalkerDate,
 47→    PlaylistMeta,
 48→    PlaylistRecentlyViewedItem,
 49→    Settings,
 50→    STORE_KEY,
 51→} from 'shared-interfaces';
 52→import { AllChannelsViewComponent } from './all-channels-view/all-channels-view.component';
 53→import { FavoritesViewComponent } from './favorites-view/favorites-view.component';
 54→import { GroupsViewComponent } from './groups-view/groups-view.component';
 55→import {
 56→    RecentViewComponent,
 57→    RecentViewItem,
 58→} from './recent-view/recent-view.component';
 59→
 60→function groupChannelsByTitle(channels: Channel[]): Record<string, Channel[]> {
 61→    return channels.reduce<Record<string, Channel[]>>((groups, channel) => {
 62→        const key = channel.group?.title ?? '';
 63→        if (!groups[key]) {
 64→            groups[key] = [];
 65→        }
 66→        groups[key].push(channel);
 67→        return groups;
 68→    }, {});
 69→}
 70→
 71→@Component({
 72→    selector: 'app-channel-list-container',
 73→    templateUrl: './channel-list-container.component.html',
 74→    styleUrls: ['./channel-list-container.component.scss'],
 75→    changeDetection: ChangeDetectionStrategy.OnPush,
 76→    imports: [
 77→        AllChannelsViewComponent,
 78→        CommonModule,
 79→        FavoritesViewComponent,
 80→        GroupsViewComponent,
 81→        MatButtonModule,
 82→        MatIconModule,
 83→        RecentViewComponent,
 84→        TranslatePipe,
 85→    ],
 86→})
 87→export class ChannelListContainerComponent implements OnInit, OnDestroy {
 88→    private readonly epgService = inject(EpgService);
 89→    private readonly playlistsService = inject(PlaylistsService);
 90→    private readonly storage = inject(StorageMap);
 91→    private readonly store = inject(Store);
 92→    private readonly router = inject(Router);
 93→    private readonly route = inject(ActivatedRoute);
 94→
 95→    /** Map of channel ID to current EPG program */
 96→    readonly channelEpgMap = signal(new Map<string, EpgProgram | null>());
 97→
 98→    /** Interval for refreshing EPG data */
 99→    private epgRefreshInterval?: number;
100→
101→    /** Global progress tick signal - triggers re-computation of progress percentages */
102→    readonly progressTick = signal(0);
103→
104→    /** Interval for global progress updates */
105→    private progressInterval?: number;
106→
107→    /** Whether to show EPG data in channel items */
108→    readonly shouldShowEpg = signal(false);
109→
110→    /** Item size for virtual scroll - compact when no EPG */
111→    readonly itemSize = computed(() => (this.shouldShowEpg() ? 68 : 48));
112→
113→    /** Active view (all, groups, favorites, recent) */
114→    readonly activeView = input<string>('all');
115→    readonly recentItems = input<PlaylistRecentlyViewedItem[]>([]);
116→    readonly isWorkspaceLayout = isWorkspaceLayoutRoute(this.route);
117→    private readonly routeSearchTerm = queryParamSignal(
118→        this.route,
119→        'q',
120→        (value) => (value ?? '').trim().toLowerCase()
121→    );
122→    readonly workspaceSearchTerm = computed(() =>
123→        this.isWorkspaceLayout ? this.routeSearchTerm() : ''
124→    );
125→
126→    readonly currentUrl = toSignal(
127→        this.router.events.pipe(
128→            filter((event) => event instanceof NavigationEnd),
129→            map((event) => (event as NavigationEnd).urlAfterRedirects)
130→        ),
131→        { initialValue: this.router.url }
132→    );
133→
134→    readonly viewTitle = computed(() => {
135→        const view = this.activeView();
136→        const url = this.currentUrl();
137→        if (view === 'all') return 'CHANNELS.ALL_CHANNELS';
138→        if (view === 'groups') return 'CHANNELS.GROUPS';
139→        if (view === 'recent') return 'PORTALS.SIDEBAR.RECENT';
140→        if (view === 'favorites') {
141→            return url.includes('/workspace/global-favorites')
142→                ? 'HOME.PLAYLISTS.GLOBAL_FAVORITES'
143→                : 'CHANNELS.FAVORITES';
144→        }
145→        return '';
146→    });
147→
148→    /** Channels array */
149→    _channelList: Channel[] = [];
150→    private readonly channelListSignal = signal<Channel[]>([]);
151→    private channelList$ = new BehaviorSubject<Channel[]>([]);
152→
153→    get channelList(): Channel[] {
154→        return this._channelList;
155→    }
156→
157→    @Input()
158→    set channelList(value: Channel[]) {
159→        const safeValue = value ?? [];
160→        this._channelList = safeValue;
161→        this.channelListSignal.set(safeValue);
162→        this.channelList$.next(safeValue);
163→        this.fetchEpgForChannels(safeValue);
164→    }
165→
166→    /** Active playlist ID as signal */
167→    private readonly activePlaylistIdSignal = this.store.selectSignal(
168→        selectActivePlaylistId
169→    );
170→
171→    /** Displayed channels - filters out unfavorited channels in global favorites view */
172→    readonly displayedChannels = computed(() => {
173→        return this.channelListSignal();
174→    });
175→
176→    /** Object with channels sorted by groups */
177→    readonly groupedChannels = computed(() =>
178→        groupChannelsByTitle(this.displayedChannels())
179→    );
180→
181→    readonly recentChannelItems = computed<RecentViewItem[]>(() => {
182→        const channels = this.channelListSignal();
183→        const recentItems = this.recentItems();
184→        const channelsByUrl = new Map(
185→            channels.map((channel) => [channel.url, channel] as const)
186→        );
187→        const channelsById = new Map(
188→            channels.map((channel) => [channel.id, channel] as const)
189→        );
190→        const seenUrls = new Set<string>();
191→
192→        return [...recentItems]
193→            .filter(isM3uRecentlyViewedItem)
194→            .sort(
195→                (a, b) =>
196→                    new Date(normalizeStalkerDate(b.added_at)).getTime() -
197→                    new Date(normalizeStalkerDate(a.added_at)).getTime()
198→            )
199→            .reduce<RecentViewItem[]>((acc, item) => {
200→                const channelUrl = item.url?.trim();
201→                if (!channelUrl || seenUrls.has(channelUrl)) {
202→                    return acc;
203→                }
204→
205→                const channel =
206→                    channelsByUrl.get(channelUrl) ||
207→                    (item.channel_id
208→                        ? channelsById.get(item.channel_id)
209→                        : undefined);
210→
211→                if (!channel) {
212→                    return acc;
213→                }
214→
215→                seenUrls.add(channel.url);
216→                acc.push({
217→                    channel,
218→                    viewedAt: normalizeStalkerDate(item.added_at),
219→                });
220→                return acc;
221→            }, []);
222→    });
223→
224→    /** Selected channel */
225→    readonly activeChannel = this.store.selectSignal(selectActive);
226→
227→    /** Active channel URL for highlighting */
228→    readonly activeChannelUrl = computed(() => this.activeChannel()?.url);
229→
230→    /** ID of the current playlist */
231→    playlistId$ = this.store
232→        .select(selectActivePlaylistId)
233→        .pipe(
234→            skipWhile(
235→                (playlistId) => playlistId === '' || playlistId === undefined
236→            )
237→        );
238→
239→    /** Set of favorite channel URLs for quick lookup */
240→    private readonly _favorites = this.store.selectSignal(selectFavorites);
241→    readonly favoriteIds = computed(() => new Set(this._favorites()));
242→
243→    /** List with favorites */
244→    favorites$ = combineLatest([
245→        this.store.select(selectFavorites),
246→        this.channelList$,
247→    ]).pipe(
248→        map(([favoriteChannelIds, channelList]) => {
249→            return favoriteChannelIds
250→                .map((favoriteChannelId) =>
251→                    channelList.find(
252→                        (channel) => channel.url === favoriteChannelId
253→                    )
254→                )
255→                .filter((channel): channel is Channel => channel !== undefined);
256→        })
257→    );
258→
259→    ngOnInit(): void {
260→        // Check if EPG should be shown (only in Electron with configured EPG URL)
261→        const isElectron = !!window['electron'];
262→        if (isElectron) {
263→            this.storage
264→                .get(STORE_KEY.Settings)
265→                .subscribe((settings: unknown) => {
266→                    if (
267→                        settings &&
268→                        Object.keys(settings as Settings).length > 0
269→                    ) {
270→                        const epgUrl = (settings as Settings).epgUrl;
271→                        this.shouldShowEpg.set(!!(epgUrl && epgUrl.length > 0));
272→                    }
273→                });
274→        } else {
275→            this.shouldShowEpg.set(false);
276→        }
277→
278→        // Set up EPG refresh interval (every 60 seconds)
279→        this.epgRefreshInterval = window.setInterval(() => {
280→            this.fetchEpgForChannels(this._channelList);
281→        }, 60000);
282→
283→        // Set up global progress update interval (every 30 seconds)
284→        this.progressInterval = window.setInterval(() => {
285→            this.progressTick.update((v) => v + 1);
286→        }, 30000);
287→    }
288→
289→    ngOnDestroy(): void {
290→        this.store.dispatch(ChannelActions.resetActiveChannel());
291→        this.store.dispatch(ChannelActions.setChannels({ channels: [] }));
292→
293→        if (this.epgRefreshInterval) {
294→            clearInterval(this.epgRefreshInterval);
295→        }
296→
297→        if (this.progressInterval) {
298→            clearInterval(this.progressInterval);
299→        }
300→
301→        this.channelList$.complete();
302→    }
303→
304→    /**
305→     * Fetches EPG data for all channels
306→     */
307→    private fetchEpgForChannels(channels: Channel[]): void {
308→        if (!channels || channels.length === 0) {
309→            return;
310→        }
311→
312→        const channelIds = channels
313→            .map((channel) => channel?.tvg?.id?.trim() || channel?.name?.trim())
314→            .filter((id) => !!id);
315→
316→        this.epgService
317→            .getCurrentProgramsForChannels(channelIds)
318→            .subscribe((epgMap) => {
319→                this.channelEpgMap.set(epgMap);
320→            });
321→    }
322→
323→    /**
324→     * Handles channel selection from any tab
325→     */
326→    onChannelSelected(channel: Channel): void {
327→        this.store.dispatch(ChannelActions.setActiveChannel({ channel }));
328→
329→        const epgChannelId = channel?.tvg?.id?.trim() || channel?.name.trim();
330→        if (epgChannelId) {
331→            this.epgService.getChannelPrograms(epgChannelId);
332→        }
333→    }
334→
335→    /**
336→     * Handles favorite toggle from favorites tab
337→     */
338→    onFavoriteToggled(event: { channel: Channel; event: MouseEvent }): void {
339→        event.event.stopPropagation();
340→        this.store.dispatch(
341→            FavoritesActions.updateFavorites({ channel: event.channel })
342→        );
343→    }
344→
345→    /**
346→     * Handles favorites reorder from drag-drop
347→     */
348→    onFavoritesReordered(channelIds: string[]): void {
349→        this.store.dispatch(FavoritesActions.setFavorites({ channelIds }));
350→    }
351→
352→    async removeRecentChannel(channelUrl: string): Promise<void> {
353→        const playlistId = this.activePlaylistIdSignal();
354→        if (!playlistId) {
355→            return;
356→        }
357→
358→        const updatedPlaylist = await firstValueFrom(
359→            this.playlistsService.removeFromM3uRecentlyViewed(
360→                playlistId,
361→                channelUrl
362→            )
363→        );
364→
365→        this.store.dispatch(
366→            PlaylistActions.updatePlaylistMeta({
367→                playlist: {
368→                    _id: playlistId,
369→                    recentlyViewed: updatedPlaylist?.recentlyViewed ?? [],
370→                } as PlaylistMeta,
371→            }) as any
372→        );
373→    }
374→
375→    async clearRecentChannels(): Promise<void> {
376→        const playlistId = this.activePlaylistIdSignal();
377→        if (!playlistId) {
378→            return;
379→        }
380→
381→        const updatedPlaylist = await firstValueFrom(
382→            this.playlistsService.clearM3uRecentlyViewed(playlistId)
383→        );
384→
385→        this.store.dispatch(
386→            PlaylistActions.updatePlaylistMeta({
387→                playlist: {
388→                    _id: playlistId,
389→                    recentlyViewed: updatedPlaylist?.recentlyViewed ?? [],
390→                } as PlaylistMeta,
391→            }) as any
392→        );
393→    }
394→}
