  1→import {
  2→    CdkDragDrop,
  3→    DragDropModule,
  4→    moveItemInArray,
  5→} from '@angular/cdk/drag-drop';
  6→import {
  7→    ChangeDetectionStrategy,
  8→    Component,
  9→    computed,
 10→    input,
 11→    output,
 12→} from '@angular/core';
 13→import { TranslatePipe } from '@ngx-translate/core';
 14→import { Channel, EpgProgram } from 'shared-interfaces';
 15→import { EnrichedChannel } from '../all-channels-view/all-channels-view.component';
 16→import { ChannelListItemComponent } from '../channel-list-item/channel-list-item.component';
 17→
 18→@Component({
 19→    selector: 'app-favorites-view',
 20→    templateUrl: './favorites-view.component.html',
 21→    styleUrls: ['./favorites-view.component.scss'],
 22→    changeDetection: ChangeDetectionStrategy.OnPush,
 23→    imports: [ChannelListItemComponent, DragDropModule, TranslatePipe],
 24→})
 25→export class FavoritesViewComponent {
 26→    /** Favorite channels */
 27→    readonly favorites = input.required<Channel[]>();
 28→    readonly searchTerm = input('');
 29→
 30→    /** EPG map for channel enrichment */
 31→    readonly channelEpgMap = input.required<Map<string, EpgProgram | null>>();
 32→
 33→    /** Progress tick to trigger progress recalculation */
 34→    readonly progressTick = input.required<number>();
 35→
 36→    /** Whether to show EPG data */
 37→    readonly shouldShowEpg = input.required<boolean>();
 38→
 39→    /** Currently active channel URL */
 40→    readonly activeChannelUrl = input<string | undefined>();
 41→
 42→    /** Emits when a channel is selected */
 43→    readonly channelSelected = output<Channel>();
 44→
 45→    /** Emits when favorite is toggled (removed) */
 46→    readonly favoriteToggled = output<{
 47→        channel: Channel;
 48→        event: MouseEvent;
 49→    }>();
 50→
 51→    /** Emits when favorites order changes via drag-drop */
 52→    readonly favoritesReordered = output<string[]>();
 53→
 54→    readonly hasSearchTerm = computed(() => this.searchTerm().trim().length > 0);
 55→    readonly filteredFavorites = computed(() => {
 56→        const favorites = this.favorites();
 57→        const term = this.searchTerm().trim().toLowerCase();
 58→
 59→        if (!term) {
 60→            return favorites;
 61→        }
 62→
 63→        return favorites.filter((channel) =>
 64→            `${channel.name ?? ''} ${channel.group?.title ?? ''}`
 65→                .toLowerCase()
 66→                .includes(term)
 67→        );
 68→    });
 69→
 70→    /**
 71→     * Computed signal for enriched favorites with EPG data
 72→     */
 73→    readonly enrichedFavorites = computed(() => {
 74→        const favorites = this.filteredFavorites();
 75→        const epgMap = this.channelEpgMap();
 76→        // Read progressTick to trigger recalculation
 77→        this.progressTick();
 78→
 79→        return favorites.map((channel) => {
 80→            const channelId = channel?.tvg?.id?.trim() || channel?.name?.trim();
 81→            const epgProgram = channelId ? epgMap.get(channelId) : null;
 82→            return {
 83→                ...channel,
 84→                epgProgram,
 85→                progressPercentage: this.calculateProgress(epgProgram),
 86→            } as EnrichedChannel;
 87→        });
 88→    });
 89→
 90→    /**
 91→     * Calculates progress percentage for an EPG program
 92→     */
 93→    private calculateProgress(
 94→        epgProgram: EpgProgram | null | undefined
 95→    ): number {
 96→        if (!epgProgram) {
 97→            return 0;
 98→        }
 99→
100→        const now = new Date().getTime();
101→        const start = new Date(epgProgram.start).getTime();
102→        const stop = new Date(epgProgram.stop).getTime();
103→
104→        const total = stop - start;
105→        const elapsed = now - start;
106→
