22→    imports: [ChannelListItemComponent, TranslatePipe],
23→})
24→export class RecentViewComponent {
25→    readonly recentItems = input.required<RecentViewItem[]>();
26→    readonly searchTerm = input('');
27→    readonly channelEpgMap = input.required<Map<string, EpgProgram | null>>();
28→    readonly progressTick = input.required<number>();
29→    readonly shouldShowEpg = input.required<boolean>();
30→    readonly activeChannelUrl = input<string | undefined>();
31→
32→    readonly channelSelected = output<Channel>();
33→    readonly removeRecent = output<string>();
34→
35→    readonly filteredRecentItems = computed(() => {
36→        const recentItems = this.recentItems();
37→        const term = this.searchTerm().trim().toLowerCase();
38→
39→        if (!term) {
40→            return recentItems;
41→        }
42→
43→        return recentItems.filter(({ channel }) =>
44→            `${channel.name ?? ''} ${channel.group?.title ?? ''}`
45→                .toLowerCase()
46→                .includes(term)
47→        );
48→    });
49→
50→    readonly enrichedRecentItems = computed(() => {
51→        const recentItems = this.filteredRecentItems();
52→        const epgMap = this.channelEpgMap();
53→        this.progressTick();
54→
55→        return recentItems.map(({ channel, viewedAt }) => {
56→            const channelId = channel?.tvg?.id?.trim() || channel?.name?.trim();
57→            const epgProgram = channelId ? epgMap.get(channelId) : null;
58→
59→            return {
60→                channel,
61→                viewedAt,
62→                epgProgram,
63→                progressPercentage: this.calculateProgress(epgProgram),
64→            };
