74→
75→        const now = new Date().getTime();
76→        const start = new Date(epgProgram.start).getTime();
77→        const stop = new Date(epgProgram.stop).getTime();
78→        const total = stop - start;
79→        const elapsed = now - start;
80→
81→        return Math.min(100, Math.max(0, (elapsed / total) * 100));
82→    }
