429→
430→        if (this.isGlobal) {
431→            this.dialogRef?.close();
432→            const navigation = buildXtreamNavigationTarget({
433→                playlistId: item.playlist_id,
434→                type: item.type,
435→                categoryId: item.category_id,
436→                itemId: item.xtream_id,
