  1→/**
  2→ * GlobalFavoritesService
  3→ *
  4→ * Aggregates live TV favorites from all three playlist source types:
  5→ * - M3U   – channels whose URL/id is listed in playlist.favorites[]
  6→ * - Xtream – rows in the `favorites` DB table where content.type = 'live'
  7→ * - Stalker – items in playlist.favorites[] that have a `cmd` (live channels)
  8→ *             and do NOT have movie_id / series_id
  9→ *
 10→ * Also handles reordering: persists position for Xtream rows via IPC.
 11→ * For M3U and Stalker the list order is managed in the app_state table
 12→ * as a JSON array of UIDs (keyed by GLOBAL_FAVORITES_ORDER_KEY).
 13→ */
 14→import { inject, Injectable } from '@angular/core';
 15→import { Store } from '@ngrx/store';
 16→import { TranslateService } from '@ngx-translate/core';
 17→import { selectAllPlaylistsMeta } from 'm3u-state';
 18→import { firstValueFrom, map } from 'rxjs';
 19→import { DatabaseService, PlaylistsService } from 'services';
 20→import {
 21→    Channel,
 22→    Playlist,
 23→    PlaylistMeta,
 24→    StalkerPortalItem,
 25→} from 'shared-interfaces';
 26→import {
 27→    buildFavoriteUid,
 28→    UnifiedFavoriteChannel,
 29→} from '@iptvnator/portal/shared/util';
 30→
 31→const GLOBAL_FAVORITES_ORDER_KEY = 'global-favorites-channel-order-v1';
 32→
 33→interface XtreamGlobalFavoriteRow {
 34→    readonly added_at?: string | null;
 35→    readonly id: number;
 36→    readonly playlist_id: string;
 37→    readonly playlist_name: string;
 38→    readonly position?: number | null;
 39→    readonly poster_url?: string | null;
 40→    readonly title: string;
 41→    readonly xtream_id: number;
 42→}
 43→
 44→type PlaylistWithChannels = Playlist & {
 45→    readonly playlist?: {
 46→        readonly items?: Channel[];
 47→    };
 48→};
 49→
 50→function isStalkerFavoriteItem(
 51→    value: string | StalkerPortalItem
 52→): value is StalkerPortalItem {
 53→    return typeof value !== 'string';
 54→}
 55→
 56→@Injectable({ providedIn: 'root' })
 57→export class GlobalFavoritesService {
 58→    private readonly store = inject(Store);
 59→    private readonly dbService = inject(DatabaseService);
 60→    private readonly playlistsService = inject(PlaylistsService);
 61→    private readonly translate = inject(TranslateService);
 62→
 63→    /**
 64→     * Fetch and merge live TV favorites from all source types.
 65→     * The returned list is sorted by persisted position first,
 66→     * then by addedAt descending for items without a position.
 67→     */
 68→    async getUnifiedLiveFavorites(): Promise<UnifiedFavoriteChannel[]> {
 69→        const [m3uItems, xtreamItems, stalkerItems, savedOrder] =
 70→            await Promise.all([
 71→                this.getM3uFavorites(),
 72→                this.getXtreamLiveFavorites(),
 73→                this.getStalkerLiveFavorites(),
 74→                this.getSavedOrder(),
 75→            ]);
 76→
 77→        const all = [...m3uItems, ...xtreamItems, ...stalkerItems];
 78→
 79→        return this.applyOrder(all, savedOrder);
 80→    }
 81→
 82→    /**
 83→     * Remove a channel from its source playlist's favorites.
 84→     * Works for all three source types (M3U, Xtream, Stalker).
 85→     */
 86→    async removeFavorite(channel: UnifiedFavoriteChannel): Promise<void> {
 87→        switch (channel.sourceType) {
 88→            case 'm3u': {
 89→                const playlist = await firstValueFrom(
 90→                    this.playlistsService.getPlaylistById(channel.playlistId)
 91→                );
 92→                const currentFavs = (playlist.favorites as string[]) ?? [];
 93→                const filtered = currentFavs.filter(
 94→                    (f) => f !== channel.streamUrl
 95→                );
 96→                await firstValueFrom(
 97→                    this.playlistsService.setFavorites(
 98→                        channel.playlistId,
 99→                        filtered
100→                    )
101→                );
102→                break;
103→            }
104→            case 'xtream': {
105→                if (window.electron && channel.contentId != null) {
106→                    await window.electron.dbRemoveFavorite(
107→                        channel.contentId,
108→                        channel.playlistId
109→                    );
110→                }
111→                break;
112→            }
113→            case 'stalker': {
114→                const sourceItemId = channel.uid.split('::')[2];
115→                await firstValueFrom(
116→                    this.playlistsService.removeFromPortalFavorites(
117→                        channel.playlistId,
118→                        sourceItemId
119→                    )
120→                );
121→                break;
122→            }
123→        }
124→    }
125→
126→    /**
127→     * Persist the new display order.
128→     * For Xtream items update the DB position column.
129→     * For all items, persist the UID order in app_state.
130→     */
131→    async reorder(channels: UnifiedFavoriteChannel[]): Promise<void> {
132→        const uidOrder = channels.map((ch) => ch.uid);
133→
134→        // Persist xtream positions to DB
135→        const xtreamUpdates = channels
136→            .filter(
137→                (
138→                    ch
139→                ): ch is UnifiedFavoriteChannel & { contentId: number } =>
140→                    ch.sourceType === 'xtream' && ch.contentId != null
141→            )
142→            .map((ch, index) => ({
143→                content_id: ch.contentId,
144→                position: index,
145→            }));
146→
147→        await Promise.all([
148→            xtreamUpdates.length > 0 && window.electron
149→                ? window.electron.dbReorderGlobalFavorites(xtreamUpdates)
150→                : Promise.resolve(),
151→            this.saveOrder(uidOrder),
152→        ]);
153→    }
154→
155→    // ─── Private helpers ───────────────────────────────────────────
156→
157→    private async getM3uFavorites(): Promise<UnifiedFavoriteChannel[]> {
158→        const allMeta = await firstValueFrom(
159→            this.store
160→                .select(selectAllPlaylistsMeta)
161→                .pipe(map((metas) => metas as PlaylistMeta[]))
162→        );
163→        const m3uPlaylists = allMeta.filter(
164→            (p) => p._id && !p.serverUrl && !p.macAddress
165→        );
166→
167→        const results: UnifiedFavoriteChannel[] = [];
168→
169→        for (const meta of m3uPlaylists) {
170→            if (!meta.favorites?.length) continue;
171→            const favoriteIds = new Set(
172→                (meta.favorites as string[]).map(String)
173→            );
174→
175→            // Load full playlist to access channel items
176→            let playlist: PlaylistWithChannels | undefined;
177→            try {
178→                playlist = (await firstValueFrom(
179→                    this.playlistsService.getPlaylistById(meta._id)
180→                )) as PlaylistWithChannels | undefined;
181→            } catch {
182→                continue;
183→            }
184→
185→            const items = playlist?.playlist?.items ?? [];
186→            for (const ch of items) {
187→                if (favoriteIds.has(ch.id) || favoriteIds.has(ch.url)) {
188→                    const sourceItemId = ch.url || ch.id;
189→                    results.push({
190→                        uid: buildFavoriteUid('m3u', meta._id, sourceItemId),
191→                        name: ch.name,
192→                        logo: ch.tvg?.logo ?? null,
193→                        sourceType: 'm3u',
194→                        playlistId: meta._id,
195→                        playlistName: meta.title || meta.filename || 'M3U',
196→                        streamUrl: ch.url,
197→                        tvgId: ch.tvg?.id || ch.tvg?.name || ch.name,
198→                        addedAt: new Date(0).toISOString(),
199→                        position: 0,
200→                    });
201→                }
202→            }
203→        }
204→
205→        return results;
206→    }
207→
208→    private async getXtreamLiveFavorites(): Promise<UnifiedFavoriteChannel[]> {
209→        if (!window.electron) return [];
210→
211→        let items: XtreamGlobalFavoriteRow[] = [];
212→        try {
213→            items =
214→                (await this.dbService.getGlobalFavorites()) as XtreamGlobalFavoriteRow[];
215→        } catch {
216→            return [];
217→        }
218→
219→        // getGlobalFavorites now only returns type='live'
220→        return items.map((item) => ({
221→            uid: buildFavoriteUid('xtream', item.playlist_id, item.xtream_id),
222→            name: item.title,
223→            logo: item.poster_url ?? null,
224→            sourceType: 'xtream' as const,
225→            playlistId: item.playlist_id,
226→            playlistName: item.playlist_name,
227→            xtreamId: item.xtream_id,
228→            tvgId: String(item.xtream_id),
229→            addedAt: item.added_at ?? new Date(0).toISOString(),
230→            position: item.position ?? 0,
231→            contentId: item.id,
232→        }));
233→    }
234→
235→    private async getStalkerLiveFavorites(): Promise<UnifiedFavoriteChannel[]> {
236→        const allMeta = await firstValueFrom(
237→            this.store
238→                .select(selectAllPlaylistsMeta)
239→                .pipe(map((metas) => metas as PlaylistMeta[]))
240→        );
241→
242→        const stalkerPlaylists = allMeta.filter((p) => p._id && p.macAddress);
243→
244→        const results: UnifiedFavoriteChannel[] = [];
245→
246→        for (const meta of stalkerPlaylists) {
247→            if (!meta.favorites?.length) continue;
248→
249→            // Fetch full playlist to get credentials
250→            let playlist: Playlist | undefined;
251→            try {
252→                playlist = (await firstValueFrom(
253→                    this.playlistsService.getPlaylistById(meta._id)
254→                )) as Playlist | undefined;
255→            } catch {
256→                continue;
257→            }
258→
259→            const favorites = Array.isArray(playlist?.favorites)
260→                ? playlist.favorites.filter(isStalkerFavoriteItem)
261→                : [];
262→
263→            for (const fav of favorites) {
264→                // Live channels: have a cmd, no movie_id / series_id
265→                const isLive =
266→                    fav.cmd &&
267→                    !fav.movie_id &&
268→                    !fav.series_id &&
269→                    (fav.stream_type === 'live' ||
270→                        fav.category_id === 'itv' ||
271→                        (!fav.stream_type && !fav.series_id && !fav.movie_id));
272→                if (!isLive) continue;
273→
274→                const streamId = fav.stream_id ?? fav.id;
275→                results.push({
276→                    uid: buildFavoriteUid('stalker', meta._id, streamId),
277→                    name:
278→                        fav.o_name ||
279→                        fav.name ||
280→                        this.translate.instant(
281→                            'WORKSPACE.GLOBAL_FAVORITES.UNKNOWN_CHANNEL'
282→                        ),
283→                    logo: fav.logo ?? fav.cover ?? null,
284→                    sourceType: 'stalker' as const,
285→                    playlistId: meta._id,
286→                    playlistName:
287→                        meta.title ||
288→                        meta.filename ||
289→                        this.translate.instant(
290→                            'WORKSPACE.DASHBOARD.STALKER_PORTAL'
291→                        ),
292→                    stalkerCmd: fav.cmd,
293→                    stalkerPortalUrl: playlist.portalUrl ?? playlist.url,
294→                    stalkerMacAddress: playlist.macAddress,
295→                    addedAt: fav.added_at
296→                        ? new Date(fav.added_at).toISOString()
297→                        : new Date(0).toISOString(),
298→                    position: 0,
299→                });
300→            }
301→        }
302→
303→        return results;
304→    }
305→
306→    private async getSavedOrder(): Promise<string[]> {
307→        if (!window.electron?.dbGetAppState) return [];
308→        try {
309→            const raw = await window.electron.dbGetAppState(
310→                GLOBAL_FAVORITES_ORDER_KEY
311→            );
312→            if (!raw) return [];
313→            return JSON.parse(raw) as string[];
314→        } catch {
315→            return [];
316→        }
317→    }
318→
319→    private async saveOrder(uidOrder: string[]): Promise<void> {
320→        if (!window.electron?.dbSetAppState) return;
321→        try {
322→            await window.electron.dbSetAppState(
323→                GLOBAL_FAVORITES_ORDER_KEY,
324→                JSON.stringify(uidOrder)
325→            );
326→        } catch {
327→            // ignore
328→        }
329→    }
330→
331→    private applyOrder(
332→        channels: UnifiedFavoriteChannel[],
333→        savedOrder: string[]
334→    ): UnifiedFavoriteChannel[] {
335→        if (!savedOrder.length) {
336→            // Default: sort by addedAt descending, xtream position asc
337→            return channels.slice().sort((a, b) => {
338→                if (a.position !== b.position) return a.position - b.position;
339→                return (
340→                    new Date(b.addedAt).getTime() -
341→                    new Date(a.addedAt).getTime()
342→                );
343→            });
344→        }
345→
346→        const orderMap = new Map(savedOrder.map((uid, i) => [uid, i]));
347→        const ordered: UnifiedFavoriteChannel[] = [];
348→        const unordered: UnifiedFavoriteChannel[] = [];
349→
350→        for (const ch of channels) {
351→            const position = orderMap.get(ch.uid);
352→            if (position != null) {
353→                ordered.push({ ...ch, position });
354→            } else {
355→                unordered.push(ch);
356→            }
357→        }
358→
359→        ordered.sort((a, b) => a.position - b.position);
360→        unordered.sort(
361→            (a, b) =>
362→                new Date(b.addedAt).getTime() - new Date(a.addedAt).getTime()
363→        );
364→
365→        return [...ordered, ...unordered];
366→    }
367→}
