  1→import { inject, Injectable } from '@angular/core';
  2→import { Store } from '@ngrx/store';
  3→import { TranslateService } from '@ngx-translate/core';
  4→import { selectAllPlaylistsMeta } from 'm3u-state';
  5→import { firstValueFrom, map } from 'rxjs';
  6→import { DatabaseService, PlaylistsService } from 'services';
  7→import { Channel, Playlist, PlaylistMeta } from 'shared-interfaces';
  8→import {
  9→    buildCollectionUid,
 10→    UnifiedCollectionItem,
 11→} from './unified-collection-item.interface';
 12→import { CollectionScope } from './scope-toggle.service';
 13→import {
 14→    isStalkerItem,
 15→    stalkerContentType,
 16→    xtreamContentType,
 17→    XtreamFavoriteRow,
 18→} from './collection-helpers';
 19→
 20→const GLOBAL_FAVORITES_ORDER_KEY = 'global-favorites-channel-order-v1';
 21→
 22→type PlaylistWithChannels = Playlist & {
 23→    readonly playlist?: { readonly items?: Channel[] };
 24→};
 25→
 26→@Injectable({ providedIn: 'root' })
 27→export class UnifiedFavoritesDataService {
 28→    private readonly store = inject(Store);
 29→    private readonly dbService = inject(DatabaseService);
 30→    private readonly playlistsService = inject(PlaylistsService);
 31→    private readonly translate = inject(TranslateService);
 32→
 33→    async getFavorites(
 34→        scope: CollectionScope,
 35→        playlistId?: string,
 36→        portalType?: string
 37→    ): Promise<UnifiedCollectionItem[]> {
 38→        if (scope === 'playlist' && playlistId) {
 39→            return this.getPlaylistFavorites(playlistId, portalType);
 40→        }
 41→        return this.getAllFavorites();
 42→    }
 43→
 44→    async removeFavorite(item: UnifiedCollectionItem): Promise<void> {
 45→        switch (item.sourceType) {
 46→            case 'm3u': {
 47→                const playlist = await firstValueFrom(
 48→                    this.playlistsService.getPlaylistById(item.playlistId)
 49→                );
 50→                const filtered = ((playlist.favorites as string[]) ?? [])
 51→                    .filter((f) => f !== item.streamUrl);
 52→                await firstValueFrom(
 53→                    this.playlistsService.setFavorites(item.playlistId, filtered)
 54→                );
 55→                break;
 56→            }
 57→            case 'xtream':
 58→                if (window.electron && item.contentId != null) {
 59→                    await window.electron.dbRemoveFavorite(item.contentId, item.playlistId);
 60→                }
 61→                break;
 62→            case 'stalker': {
 63→                const sourceItemId = item.uid.split('::')[2];
 64→                await firstValueFrom(
 65→                    this.playlistsService.removeFromPortalFavorites(item.playlistId, sourceItemId)
 66→                );
 67→                break;
 68→            }
 69→        }
 70→    }
 71→
 72→    async reorder(items: UnifiedCollectionItem[]): Promise<void> {
 73→        const uidOrder = items.map((i) => i.uid);
 74→        const xtreamUpdates = items
 75→            .filter((i) => i.sourceType === 'xtream' && i.contentId != null)
 76→            .map((i, idx) => ({ content_id: i.contentId!, position: idx }));
 77→        await Promise.all([
 78→            xtreamUpdates.length > 0 && window.electron
 79→                ? window.electron.dbReorderGlobalFavorites(xtreamUpdates)
 80→                : Promise.resolve(),
 81→            this.saveOrder(uidOrder),
 82→        ]);
 83→    }
 84→
 85→    private async getAllFavorites(): Promise<UnifiedCollectionItem[]> {
 86→        const [m3u, xtream, stalker, order] = await Promise.all([
 87→            this.getM3uFavorites(),
 88→            this.getXtreamAllFavorites(),
 89→            this.getStalkerAllFavorites(),
 90→            this.getSavedOrder(),
 91→        ]);
 92→        return this.applyOrder([...m3u, ...xtream, ...stalker], order);
 93→    }
 94→
 95→    private async getPlaylistFavorites(
 96→        playlistId: string,
 97→        portalType?: string
 98→    ): Promise<UnifiedCollectionItem[]> {
 99→        if (portalType === 'xtream') return this.getXtreamPlaylistFavorites(playlistId);
100→        if (portalType === 'stalker') return this.getStalkerPlaylistFavorites(playlistId);
101→        return this.getM3uPlaylistFavorites(playlistId);
102→    }
103→
104→    private async getM3uFavorites(): Promise<UnifiedCollectionItem[]> {
105→        const allMeta = await this.getAllMeta();
106→        const results: UnifiedCollectionItem[] = [];
107→        for (const meta of allMeta.filter((p) => p._id && !p.serverUrl && !p.macAddress)) {
108→            results.push(...(await this.extractM3uFavorites(meta)));
109→        }
110→        return results;
111→    }
112→
113→    private async getM3uPlaylistFavorites(id: string): Promise<UnifiedCollectionItem[]> {
114→        const meta = await this.getPlaylistMeta(id);
115→        return meta ? this.extractM3uFavorites(meta) : [];
116→    }
117→
118→    private async extractM3uFavorites(meta: PlaylistMeta): Promise<UnifiedCollectionItem[]> {
119→        if (!meta.favorites?.length) return [];
120→        const favIds = new Set((meta.favorites as string[]).map(String));
121→        let playlist: PlaylistWithChannels | undefined;
122→        try {
123→            playlist = (await firstValueFrom(
124→                this.playlistsService.getPlaylistById(meta._id)
125→            )) as PlaylistWithChannels | undefined;
126→        } catch { return []; }
127→        return (playlist?.playlist?.items ?? [])
128→            .filter((ch) => favIds.has(ch.id) || favIds.has(ch.url))
129→            .map((ch) => ({
130→                uid: buildCollectionUid('m3u', meta._id, ch.url || ch.id),
131→                name: ch.name,
132→                contentType: 'live' as const,
133→                sourceType: 'm3u' as const,
134→                playlistId: meta._id,
135→                playlistName: meta.title || meta.filename || 'M3U',
136→                logo: ch.tvg?.logo ?? null,
137→                streamUrl: ch.url,
138→                tvgId: ch.tvg?.id || ch.tvg?.name || ch.name,
139→                addedAt: new Date(0).toISOString(),
140→                position: 0,
141→            }));
142→    }
143→
144→    private async getXtreamAllFavorites(): Promise<UnifiedCollectionItem[]> {
145→        if (!window.electron?.dbGetAllGlobalFavorites) return [];
146→        try {
147→            const rows = (await this.dbService.getAllGlobalFavorites()) as XtreamFavoriteRow[];
148→            return rows.map((r) => this.mapXtreamRow(r));
149→        } catch { return []; }
150→    }
151→
152→    private async getXtreamPlaylistFavorites(playlistId: string): Promise<UnifiedCollectionItem[]> {
153→        if (!window.electron) return [];
154→        try {
155→            const rows = await this.dbService.getFavorites(playlistId);
156→            const meta = await this.getPlaylistMeta(playlistId);
157→            return (rows as unknown as XtreamFavoriteRow[]).map((r) => ({
158→                ...this.mapXtreamRow(r),
159→                playlistId,
160→                playlistName: meta?.title || 'Xtream',
161→            }));
162→        } catch { return []; }
163→    }
164→
165→    private mapXtreamRow(row: XtreamFavoriteRow): UnifiedCollectionItem {
166→        const ct = xtreamContentType(row.type);
167→        return {
168→            uid: buildCollectionUid('xtream', row.playlist_id, row.xtream_id),
169→            name: row.title,
170→            contentType: ct,
171→            sourceType: 'xtream',
172→            playlistId: row.playlist_id,
173→            playlistName: row.playlist_name ?? 'Xtream',
174→            logo: ct === 'live' ? (row.poster_url ?? null) : null,
175→            posterUrl: ct !== 'live' ? (row.poster_url ?? null) : null,
176→            xtreamId: row.xtream_id,
177→            categoryId: row.category_id,
178→            tvgId: ct === 'live' ? String(row.xtream_id) : undefined,
179→            rating: row.rating ?? undefined,
180→            addedAt: row.added_at ?? new Date(0).toISOString(),
181→            position: row.position ?? 0,
182→            contentId: row.id,
183→        };
184→    }
185→
186→    private async getStalkerAllFavorites(): Promise<UnifiedCollectionItem[]> {
187→        const allMeta = await this.getAllMeta();
188→        const results: UnifiedCollectionItem[] = [];
189→        for (const meta of allMeta.filter((p) => p._id && p.macAddress)) {
190→            results.push(...(await this.extractStalkerFavorites(meta)));
191→        }
192→        return results;
193→    }
194→
195→    private async getStalkerPlaylistFavorites(id: string): Promise<UnifiedCollectionItem[]> {
196→        const meta = await this.getPlaylistMeta(id);
197→        return meta ? this.extractStalkerFavorites(meta) : [];
198→    }
199→
200→    private async extractStalkerFavorites(meta: PlaylistMeta): Promise<UnifiedCollectionItem[]> {
201→        if (!meta.favorites?.length) return [];
202→        let playlist: Playlist | undefined;
203→        try {
204→            playlist = (await firstValueFrom(
205→                this.playlistsService.getPlaylistById(meta._id)
206→            )) as Playlist | undefined;
207→        } catch { return []; }
208→        const favs = Array.isArray(playlist?.favorites)
209→            ? playlist.favorites.filter(isStalkerItem) : [];
210→        return favs.map((fav) => {
211→            const ct = stalkerContentType(fav);
212→            return {
213→                uid: buildCollectionUid('stalker', meta._id, fav.stream_id ?? fav.id),
214→                name: fav.o_name || fav.name || this.translate.instant('WORKSPACE.GLOBAL_FAVORITES.UNKNOWN_CHANNEL'),
215→                contentType: ct,
216→                sourceType: 'stalker' as const,
217→                playlistId: meta._id,
218→                playlistName: meta.title || meta.filename || this.translate.instant('WORKSPACE.DASHBOARD.STALKER_PORTAL'),
219→                logo: ct === 'live' ? (fav.logo ?? fav.cover ?? null) : null,
220→                posterUrl: ct !== 'live' ? (fav.logo ?? fav.cover ?? null) : null,
221→                stalkerCmd: fav.cmd,
222→                stalkerPortalUrl: playlist?.portalUrl ?? playlist?.url,
223→                stalkerMacAddress: playlist?.macAddress,
224→                categoryId: fav.category_id,
225→                stalkerItem: fav,
226→                addedAt: fav.added_at ? new Date(fav.added_at).toISOString() : new Date(0).toISOString(),
227→                position: 0,
228→            };
229→        });
230→    }
231→
232→    private async getAllMeta(): Promise<PlaylistMeta[]> {
233→        return firstValueFrom(
234→            this.store.select(selectAllPlaylistsMeta).pipe(map((m) => m as PlaylistMeta[]))
235→        );
236→    }
237→
238→    private async getPlaylistMeta(id: string): Promise<PlaylistMeta | undefined> {
239→        return (await this.getAllMeta()).find((p) => p._id === id);
240→    }
241→
242→    private async getSavedOrder(): Promise<string[]> {
243→        if (!window.electron?.dbGetAppState) return [];
244→        try {
245→            const raw = await window.electron.dbGetAppState(GLOBAL_FAVORITES_ORDER_KEY);
246→            return raw ? (JSON.parse(raw) as string[]) : [];
247→        } catch { return []; }
248→    }
249→
250→    private async saveOrder(uidOrder: string[]): Promise<void> {
251→        if (!window.electron?.dbSetAppState) return;
252→        try {
253→            await window.electron.dbSetAppState(GLOBAL_FAVORITES_ORDER_KEY, JSON.stringify(uidOrder));
254→        } catch { /* ignore */ }
255→    }
256→
257→    private applyOrder(items: UnifiedCollectionItem[], savedOrder: string[]): UnifiedCollectionItem[] {
258→        if (!savedOrder.length) {
259→            return items.slice().sort((a, b) => {
260→                const pa = a.position ?? 0, pb = b.position ?? 0;
261→                if (pa !== pb) return pa - pb;
262→                return new Date(b.addedAt ?? 0).getTime() - new Date(a.addedAt ?? 0).getTime();
263→            });
264→        }
265→        const orderMap = new Map(savedOrder.map((uid, i) => [uid, i]));
266→        const ordered: UnifiedCollectionItem[] = [];
267→        const unordered: UnifiedCollectionItem[] = [];
268→        for (const item of items) {
269→            const pos = orderMap.get(item.uid);
270→            pos != null ? ordered.push({ ...item, position: pos }) : unordered.push(item);
271→        }
272→        ordered.sort((a, b) => (a.position ?? 0) - (b.position ?? 0));
273→        unordered.sort((a, b) => new Date(b.addedAt ?? 0).getTime() - new Date(a.addedAt ?? 0).getTime());
274→        return [...ordered, ...unordered];
275→    }
276→}
