 16→import { startWith } from 'rxjs';
 17→import {
 18→    DashboardContentKind,
 19→    DashboardDataService,
 20→    DashboardWidgetConfig,
 21→    createDefaultWidgetScope,
 22→} from 'workspace-dashboard-data-access';
 23→import {
 24→    DashboardActivityItemViewModel,
 25→    DashboardActivityItemsComponent,
 26→} from './dashboard-activity-items.component';
 27→import { DashboardWidgetShellComponent } from './dashboard-widget-shell.component';
 28→
 29→const GLOBAL_FAVORITES_KIND_STORAGE_KEY =
 30→    'workspace-dashboard-global-favorites-kind';
 31→const GLOBAL_FAVORITES_VIEW_MODE_STORAGE_KEY =
 32→    'workspace-dashboard-global-favorites-view-mode';
 33→type DashboardActivityViewMode = 'list' | 'grid';
 34→const INITIAL_PAGE_SIZE = 20;
 35→const PAGE_SIZE = 20;
 36→
 37→@Component({
 38→    selector: 'app-global-favorites-widget',
 39→    imports: [
 40→        MatButtonModule,
 41→        MatButtonToggleModule,
 42→        MatMenuModule,
 43→        MatIcon,
 44→        MatTooltipModule,
 45→        DashboardActivityItemsComponent,
 46→        DashboardWidgetShellComponent,
 47→        TranslatePipe,
 48→    ],
 49→    templateUrl: './global-favorites-widget.component.html',
 50→    styleUrl: './global-favorites-widget.component.scss',
 51→})
 52→export class GlobalFavoritesWidgetComponent implements OnInit {
 53→    readonly widget = input.required<DashboardWidgetConfig>();
 54→    readonly data = inject(DashboardDataService);
 55→    private readonly translate = inject(TranslateService);
 56→    private readonly languageTick = toSignal(
 57→        this.translate.onLangChange.pipe(startWith(null)),
 58→        { initialValue: null }
 59→    );
 60→    readonly selectedKind = signal<DashboardContentKind>(
 61→        this.readStoredKind() ?? 'all'
 62→    );
 63→    readonly viewMode = signal<DashboardActivityViewMode>(
 64→        this.readStoredViewMode() ?? 'list'
 65→    );
 66→    readonly visibleItemLimit = signal(INITIAL_PAGE_SIZE);
 67→    readonly scope = computed(
 68→        () => this.widget().settings?.scope ?? createDefaultWidgetScope()
 69→    );
 70→
 71→    readonly counts = computed(() => {
 72→        const items = this.data.globalFavoriteItems();
 73→        return {
 74→            all: items.length,
 75→            channels: items.filter((item) => item.type === 'live').length,
 76→            vod: items.filter((item) => item.type === 'movie').length,
 77→            series: items.filter((item) => item.type === 'series').length,
 78→        };
 79→    });
 80→
 81→    readonly filteredItems = computed(() =>
 82→        this.data
 83→            .globalFavoriteItems()
 84→            .filter((item) =>
 85→                this.data.isTypeInKind(item.type, this.selectedKind())
 86→            )
 87→            .filter((item) =>
 88→                this.data.matchesScope(
 89→                    item.playlist_id,
 90→                    item.source,
 91→                    this.scope()
 92→                )
 93→            )
 94→    );
 95→
 96→    readonly activityItems = computed<DashboardActivityItemViewModel[]>(() =>
 97→        this.filteredItems()
 98→            .slice(0, this.visibleItemLimit())
 99→            .map((item) => ({
100→                id: `${item.id}-${item.playlist_id}-${item.added_at}`,
101→                title: item.title,
102→                subtitle: `${this.data.getFavoriteItemProviderLabel(item)} · ${this.data.getFavoriteItemTypeLabel(item)} · ${this.formatTimestamp(item.added_at)}`,
103→                type: item.type,
104→                imageUrl: item.poster_url,
105→                link: this.data.getGlobalFavoriteLink(item),
106→                navigationState:
107→                    this.data.getGlobalFavoriteNavigationState(item),
108→            }))
109→    );
110→
111→    constructor() {}
112→
113→    ngOnInit(): void {
114→        this.data.reloadGlobalFavorites().then(() => {
115→            this.visibleItemLimit.set(INITIAL_PAGE_SIZE);
116→        });
117→    }
118→
119→    onKindChange(kind: DashboardContentKind): void {
120→        this.setKind(kind);
121→    }
122→
123→    onViewModeChange(value: unknown): void {
124→        if (value === 'list' || value === 'grid') {
125→            this.viewMode.set(value);
126→            this.persistViewMode(value);
127→        }
128→    }
129→
130→    onItemsScrolledToEnd(): void {
131→        if (this.visibleItemLimit() >= this.filteredItems().length) {
132→            return;
133→        }
134→
135→        this.visibleItemLimit.update((value) => value + PAGE_SIZE);
136→    }
137→
138→    onRemoveItem(item: DashboardActivityItemViewModel): void {
139→        const globalItem = this.data
140→            .globalFavoriteItems()
141→            .find((i) => `${i.id}-${i.playlist_id}-${i.added_at}` === item.id);
142→
143→        if (globalItem) {
144→            void this.data.removeGlobalFavorite(globalItem);
145→        } else {
146→            // Fallback strategy
147→            const fallbackItem = this.data
148→                .globalFavoriteItems()
149→                .find(
150→                    (i) =>
151→                        item.link.includes(String(i.xtream_id)) ||
152→                        item.link.includes(i.playlist_id)
153→                );
154→            if (fallbackItem) {
155→                void this.data.removeGlobalFavorite(fallbackItem);
156→            }
157→        }
158→    }
159→
160→    private setKind(value: unknown): void {
161→        if (
162→            value === 'all' ||
163→            value === 'channels' ||
164→            value === 'vod' ||
165→            value === 'series'
166→        ) {
167→            this.selectedKind.set(value);
168→            this.persistKind(value);
169→            this.visibleItemLimit.set(INITIAL_PAGE_SIZE);
170→        }
171→    }
172→
173→    private readStoredKind(): DashboardContentKind | null {
174→        if (typeof localStorage === 'undefined') {
175→            return null;
176→        }
177→
178→        const value = localStorage.getItem(GLOBAL_FAVORITES_KIND_STORAGE_KEY);
179→        if (
180→            value === 'all' ||
181→            value === 'channels' ||
182→            value === 'vod' ||
183→            value === 'series'
184→        ) {
185→            return value;
186→        }
187→
188→        return null;
189→    }
190→
191→    private persistKind(kind: DashboardContentKind): void {
192→        if (typeof localStorage === 'undefined') {
193→            return;
194→        }
195→        localStorage.setItem(GLOBAL_FAVORITES_KIND_STORAGE_KEY, kind);
196→    }
197→
198→    private readStoredViewMode(): DashboardActivityViewMode | null {
199→        if (typeof localStorage === 'undefined') {
200→            return null;
201→        }
202→
203→        const value = localStorage.getItem(
204→            GLOBAL_FAVORITES_VIEW_MODE_STORAGE_KEY
205→        );
206→        return value === 'grid' || value === 'list' ? value : null;
207→    }
208→
209→    private persistViewMode(viewMode: DashboardActivityViewMode): void {
210→        if (typeof localStorage === 'undefined') {
211→            return;
212→        }
213→
214→        localStorage.setItem(GLOBAL_FAVORITES_VIEW_MODE_STORAGE_KEY, viewMode);
215→    }
216→
217→    private formatTimestamp(value: string): string {
218→        this.languageTick();
219→
220→        const date = new Date(value);
221→        if (Number.isNaN(date.getTime())) {
222→            return this.translate.instant('WORKSPACE.DASHBOARD.RECENTLY');
223→        }
224→
225→        return date.toLocaleString(
226→            this.translate.currentLang ||
227→                this.translate.defaultLang ||
228→                undefined,
229→            {
230→                month: 'short',
231→                day: 'numeric',
232→                hour: '2-digit',
233→                minute: '2-digit',
234→            }
235→        );
236→    }
237→}
