 30→    'workspace-dashboard-recently-watched-kind';
 31→const RECENTLY_WATCHED_VIEW_MODE_STORAGE_KEY =
 32→    'workspace-dashboard-recently-watched-view-mode';
 33→type DashboardActivityViewMode = 'list' | 'grid';
 34→const INITIAL_PAGE_SIZE = 20;
 35→const PAGE_SIZE = 20;
 36→
 37→@Component({
 38→    selector: 'app-recently-watched-widget',
 39→    imports: [
 40→        MatButtonModule,
 41→        MatButtonToggleModule,
 42→        MatMenuModule,
 43→        MatIcon,
 44→        MatTooltipModule,
 45→        DashboardActivityItemsComponent,
 46→        DashboardWidgetShellComponent,
 47→        TranslatePipe,
 48→    ],
 49→    templateUrl: './recently-watched-widget.component.html',
 50→    styleUrl: './recently-watched-widget.component.scss',
 51→})
 52→export class RecentlyWatchedWidgetComponent implements OnInit {
 53→    readonly widget = input.required<DashboardWidgetConfig>();
 54→    readonly data = inject(DashboardDataService);
 55→    private readonly translate = inject(TranslateService);
 56→    private readonly languageTick = toSignal(
 57→        this.translate.onLangChange.pipe(startWith(null)),
 58→        { initialValue: null }
 59→    );
 60→    readonly selectedKind = signal<DashboardContentKind>(
 61→        this.readStoredKind() ?? 'all'
 62→    );
 63→    readonly viewMode = signal<DashboardActivityViewMode>(
 64→        this.readStoredViewMode() ?? 'list'
 65→    );
 66→    readonly visibleItemLimit = signal(INITIAL_PAGE_SIZE);
 67→    readonly scope = computed(
 68→        () => this.widget().settings?.scope ?? createDefaultWidgetScope()
 69→    );
 70→
 71→    readonly counts = computed(() => {
 72→        const items = this.data.globalRecentItems();
 73→        return {
 74→            all: items.length,
 75→            channels: items.filter((item) => item.type === 'live').length,
 76→            vod: items.filter((item) => item.type === 'movie').length,
 77→            series: items.filter((item) => item.type === 'series').length,
 78→        };
 79→    });
 80→
 81→    readonly filteredItems = computed(() =>
 82→        this.data
 83→            .globalRecentItems()
 84→            .filter((item) =>
 85→                this.data.isTypeInKind(item.type, this.selectedKind())
 86→            )
 87→            .filter((item) =>
 88→                this.data.matchesScope(
 89→                    item.playlist_id,
 90→                    item.source,
 91→                    this.scope()
 92→                )
 93→            )
 94→    );
 95→
 96→    readonly activityItems = computed<DashboardActivityItemViewModel[]>(() =>
 97→        this.filteredItems()
 98→            .slice(0, this.visibleItemLimit())
 99→            .map((item) => ({
100→                id: `${item.id}-${item.playlist_id}-${item.viewed_at}`,
101→                title: item.title,
102→                subtitle: `${this.data.getRecentItemProviderLabel(item)} · ${this.data.getRecentItemTypeLabel(item)} · ${this.formatTimestamp(item.viewed_at)}`,
103→                type: item.type,
104→                imageUrl: item.poster_url,
105→                link: this.data.getRecentItemLink(item),
106→                navigationState: this.data.getRecentItemNavigationState(item),
107→            }))
108→    );
109→
110→    constructor() {}
111→
112→    ngOnInit(): void {
113→        this.data.reloadGlobalRecentItems().then(() => {
114→            this.visibleItemLimit.set(INITIAL_PAGE_SIZE);
115→        });
116→    }
117→
118→    onKindChange(kind: DashboardContentKind): void {
119→        this.setKind(kind);
120→    }
121→
122→    onViewModeChange(value: unknown): void {
123→        if (value === 'list' || value === 'grid') {
124→            this.viewMode.set(value);
125→            this.persistViewMode(value);
126→        }
127→    }
128→
129→    onItemsScrolledToEnd(): void {
130→        if (this.visibleItemLimit() >= this.filteredItems().length) {
131→            return;
132→        }
133→
134→        this.visibleItemLimit.update((value) => value + PAGE_SIZE);
135→    }
136→
137→    onRemoveItem(item: DashboardActivityItemViewModel): void {
138→        const globalItem = this.data
139→            .globalRecentItems()
140→            .find((i) => `${i.id}-${i.playlist_id}-${i.viewed_at}` === item.id);
141→
142→        if (globalItem) {
143→            void this.data.removeGlobalRecentItem(globalItem);
144→        } else {
145→            // Fallback strategy if custom ID mapping changed
146→            const fallbackItem = this.data
147→                .globalRecentItems()
148→                .find(
149→                    (i) =>
150→                        item.link.includes(String(i.xtream_id)) ||
151→                        item.link.includes(i.playlist_id)
152→                );
153→            if (fallbackItem) {
154→                void this.data.removeGlobalRecentItem(fallbackItem);
155→            }
156→        }
157→    }
158→
159→    private setKind(value: unknown): void {
160→        if (
161→            value === 'all' ||
162→            value === 'channels' ||
163→            value === 'vod' ||
164→            value === 'series'
165→        ) {
166→            this.selectedKind.set(value);
167→            this.persistKind(value);
168→            this.visibleItemLimit.set(INITIAL_PAGE_SIZE);
169→        }
170→    }
171→
172→    private readStoredKind(): DashboardContentKind | null {
173→        if (typeof localStorage === 'undefined') {
174→            return null;
175→        }
176→
177→        const value = localStorage.getItem(RECENTLY_WATCHED_KIND_STORAGE_KEY);
178→        if (
179→            value === 'all' ||
180→            value === 'channels' ||
181→            value === 'vod' ||
182→            value === 'series'
183→        ) {
184→            return value;
185→        }
186→
187→        return null;
188→    }
189→
190→    private persistKind(kind: DashboardContentKind): void {
191→        if (typeof localStorage === 'undefined') {
192→            return;
193→        }
194→        localStorage.setItem(RECENTLY_WATCHED_KIND_STORAGE_KEY, kind);
195→    }
196→
197→    private readStoredViewMode(): DashboardActivityViewMode | null {
198→        if (typeof localStorage === 'undefined') {
199→            return null;
200→        }
201→
202→        const value = localStorage.getItem(
203→            RECENTLY_WATCHED_VIEW_MODE_STORAGE_KEY
204→        );
205→        return value === 'grid' || value === 'list' ? value : null;
206→    }
207→
208→    private persistViewMode(viewMode: DashboardActivityViewMode): void {
209→        if (typeof localStorage === 'undefined') {
210→            return;
211→        }
212→
213→        localStorage.setItem(RECENTLY_WATCHED_VIEW_MODE_STORAGE_KEY, viewMode);
214→    }
215→
216→    private formatTimestamp(value: string): string {
217→        this.languageTick();
218→
219→        const date = new Date(value);
220→        if (Number.isNaN(date.getTime())) {
221→            return this.translate.instant('WORKSPACE.DASHBOARD.RECENTLY');
222→        }
223→
224→        return date.toLocaleString(
225→            this.translate.currentLang ||
226→                this.translate.defaultLang ||
227→                undefined,
228→            {
229→                month: 'short',
230→                day: 'numeric',
231→                hour: '2-digit',
232→                minute: '2-digit',
233→            }
234→        );
235→    }
236→}
