 76→}
 77→
 78→interface XtreamRecentLiveItem {
 79→    readonly id?: string | number;
 80→    readonly poster_url?: string;
 81→    readonly stream_icon?: string;
 82→    readonly title?: string;
 83→    readonly xtream_id: number;
 84→}
 85→
 86→function groupItemsByPlaylistName(
 87→    items: XtreamRecentViewItem[]
 88→): Record<string, XtreamRecentViewItem[]> {
 89→    return items.reduce<Record<string, XtreamRecentViewItem[]>>(
 90→        (groups, item) => {
 91→            const key = String(item.playlist_name);
 92→            if (!groups[key]) {
 93→                groups[key] = [];
 94→            }
 95→            groups[key].push(item);
 96→            return groups;
 97→        },
 98→        {}
 99→    );
100→}
101→
102→function isXtreamRecentViewItem(
103→    item: FavoriteLayoutItem
104→): item is XtreamRecentViewItem {
105→    return (
106→        (typeof item.id === 'number' || typeof item.id === 'string') &&
107→        typeof item.playlist_id === 'string' &&
108→        typeof item.title === 'string' &&
109→        typeof item.xtream_id !== 'undefined' &&
