123→        MatCheckboxModule,
124→        MatIcon,
125→        MatIconButton,
126→        MatMenuModule,
127→        MatTooltipModule,
128→        PortalChannelsListComponent,
129→        PortalCollectionLiveShellComponent,
130→        PortalCollectionShellComponent,
131→        TranslatePipe,
132→    ],
133→    providers: [],
134→    templateUrl: './recently-viewed.component.html',
135→    styleUrl: './recently-viewed.component.scss',
136→})
137→export class RecentlyViewedComponent {
138→    private static readonly GROUP_BY_STORAGE_KEY =
139→        'global-recent-group-by-playlist';
140→    private static readonly TYPE_FILTERS_STORAGE_KEY =
141→        'global-recent-type-filters';
142→    private static readonly MAX_FLAT_GLOBAL_ITEMS = 250;
143→
144→    private xtreamStore = inject(XtreamStore);
145→    private activatedRoute = inject(ActivatedRoute);
146→    private router = inject(Router);
147→    private readonly dbService = inject(DatabaseService);
148→    private readonly playlistsService = inject(PlaylistsService);
149→    private readonly portalPlayer = inject(PORTAL_PLAYER);
150→    private dialogData = inject(MAT_DIALOG_DATA, { optional: true });
151→    private readonly logger = createLogger('XtreamRecentlyViewed');
152→    private readonly collectionCtx = inject(PortalCollectionContextService);
153→
154→    readonly isGlobal = this.dialogData?.isGlobal ?? false;
155→    readonly isWorkspaceLayout = isWorkspaceLayoutRoute(this.activatedRoute);
156→    readonly nonGlobalLayout: PortalCollectionShellLayout = {
157→        ...XTREAM_RECENT_LAYOUT,
158→        showHeaderAction: !this.isWorkspaceLayout,
159→    };
160→    readonly playlistSubtitle = 'Xtream Code';
161→    private readonly _groupByPlaylist = (() => {
162→        const saved = localStorage.getItem(
163→            RecentlyViewedComponent.GROUP_BY_STORAGE_KEY
164→        );
165→        return signal(saved !== 'false');
166→    })();
167→    readonly groupByPlaylist = computed(() => this._groupByPlaylist());
168→    private readonly _typeFilters = (() => {
169→        const saved = localStorage.getItem(
170→            RecentlyViewedComponent.TYPE_FILTERS_STORAGE_KEY
171→        );
172→        if (!saved) {
173→            return signal({ live: true, movie: true, series: true });
174→        }
175→        try {
176→            const parsed = JSON.parse(saved) as {
177→                live?: boolean;
178→                movie?: boolean;
179→                series?: boolean;
180→            };
181→            return signal({
182→                live: parsed.live !== false,
183→                movie: parsed.movie !== false,
184→                series: parsed.series !== false,
185→            });
186→        } catch {
187→            return signal({ live: true, movie: true, series: true });
188→        }
189→    })();
190→    readonly typeFilters = computed(() => this._typeFilters());
191→    readonly recentItems = computed<XtreamRecentViewItem[]>(() =>
192→        (this.isGlobal
193→            ? this.xtreamStore.globalRecentItems()
194→            : this.xtreamStore.recentItems()) as XtreamRecentViewItem[]
195→    );
196→    readonly categories = computed(() => {
197→        const items = this.recentItems();
198→        const movies = items.filter((item) => item.type === 'movie').length;
199→        const live = items.filter((item) => item.type === 'live').length;
200→        const series = items.filter((item) => item.type === 'series').length;
201→
202→        return buildStandardCollectionCategories({
203→            labels: XTREAM_COLLECTION_LABELS,
204→            counts: {
205→                all: items.length,
206→                movie: movies,
207→                live,
208→                series,
209→            },
210→            includeLive: true,
211→        });
212→    });
213→    readonly collectionContext = createPortalCollectionContext({
214→        ctx: this.collectionCtx,
215→        categories: this.categories,
216→        enabled: () => !this.isGlobal,
217→    });
218→    readonly selectedLiveItem = signal<XtreamRecentLiveItem | null>(null);
219→    readonly liveStreamUrl = signal('');
220→    readonly nonGlobalMode = computed<PortalCollectionMode>(() =>
221→        this.isLiveCategory() ? 'live' : 'grid'
222→    );
223→    readonly selectedCategoryId = this.collectionContext.selectedCategoryId;
224→    readonly recentSearchTerm = signal('');
225→    readonly workspaceSearchTerm = queryParamSignal(
226→        this.activatedRoute,
227→        'q',
228→        (value) => (value ?? '').trim().toLowerCase()
229→    );
230→    readonly filteredRecentItems = computed(() => {
231→        const term =
232→            this.isWorkspaceLayout && !this.isGlobal
233→                ? this.workspaceSearchTerm()
234→                : this.recentSearchTerm().trim().toLowerCase();
235→        const typeFilters = this.typeFilters();
236→        const items = this.recentItems().filter((item) => {
237→            if (item.type === 'live') return typeFilters.live;
238→            if (item.type === 'movie') return typeFilters.movie;
239→            if (item.type === 'series') return typeFilters.series;
240→            return true;
241→        });
242→        if (!term) return items;
243→
244→        return items.filter((item) =>
245→            `${item.title} ${item.playlist_name ?? ''}`
246→                .toLowerCase()
247→                .includes(term)
248→        );
249→    });
250→    readonly visibleRecentItems = computed(() => {
251→        const items = this.filteredRecentItems();
252→        if (this.isGlobal && !this.groupByPlaylist()) {
253→            return items.slice(
254→                0,
255→                RecentlyViewedComponent.MAX_FLAT_GLOBAL_ITEMS
256→            );
257→        }
258→        return items;
259→    });
260→    readonly nonGlobalItemsToShow = computed(() => {
261→        const items = this.visibleRecentItems();
262→        return filterCollectionBucket({
263→            selectedCategoryId: this.selectedCategoryId(),
264→            allItems: items,
265→            buckets: {
266→                movie: items.filter((item) => item.type === 'movie'),
267→                live: items.filter((item) => item.type === 'live'),
268→                series: items.filter((item) => item.type === 'series'),
269→            },
270→            textOf: (item) => `${item.title} ${item.playlist_name ?? ''}`,
271→        });
272→    });
273→    readonly liveItemsToShow = computed<XtreamRecentLiveItem[]>(() =>
274→        this.visibleRecentItems()
275→            .filter((item) => {
276→                if (item.type !== 'live') {
277→                    return false;
278→                }
279→
280→                const term =
281→                    this.isWorkspaceLayout && !this.isGlobal
282→                        ? this.workspaceSearchTerm()
283→                        : this.recentSearchTerm().trim().toLowerCase();
284→                if (!term) {
285→                    return true;
286→                }
287→
288→                return `${item.title} ${item.playlist_name ?? ''}`
289→                    .toLowerCase()
290→                    .includes(term);
291→            })
292→            .map((item) => ({
293→                id: item.id,
294→                poster_url: item.poster_url,
295→                stream_icon: item.stream_icon,
296→                title: item.title,
297→                xtream_id: Number(item.xtream_id),
298→            }))
299→    );
300→    readonly isLiveCategory = computed(() => this.selectedCategoryId() === 'live');
301→    readonly isEmbeddedPlayer = computed(() =>
302→        this.portalPlayer.isEmbeddedPlayer()
303→    );
304→    readonly liveChannelSortMode = signal<LiveChannelSortMode>('server');
305→    readonly liveChannelSortLabel = computed(() => {
306→        const mode = this.liveChannelSortMode();
307→        if (mode === 'name-asc') return 'Name A-Z';
308→        if (mode === 'name-desc') return 'Name Z-A';
309→        return 'Server Order';
310→    });
311→    readonly currentPlaylist = this.xtreamStore.currentPlaylist;
312→    readonly playlistTitle = computed(
313→        () =>
314→            this.currentPlaylist()?.name ||
315→            this.currentPlaylist()?.title ||
316→            'Playlist'
317→    );
318→    readonly epgItems = this.xtreamStore.epgItems;
319→    readonly isLoadingEpg = this.xtreamStore.isLoadingEpg;
320→
321→    constructor(
322→        @Optional() public dialogRef?: MatDialogRef<RecentlyViewedComponent>
323→    ) {
324→        this.xtreamStore.setSelectedContentType(undefined);
325→        const savedSortMode = localStorage.getItem(
326→            XTREAM_RECENT_LIVE_SORT_STORAGE_KEY
327→        );
328→        if (
329→            savedSortMode === 'server' ||
330→            savedSortMode === 'name-asc' ||
331→            savedSortMode === 'name-desc'
332→        ) {
333→            this.liveChannelSortMode.set(savedSortMode);
334→        }
335→
336→        effect(() => {
337→            if (this.isGlobal) {
338→                return;
339→            }
340→
341→            const selectedItem = this.selectedLiveItem();
342→            if (!selectedItem) {
343→                return;
344→            }
345→
346→            const stillExists = this.liveItemsToShow().some(
347→                (item) =>
348→                    Number(item.xtream_id ?? item.id) ===
349→                    Number(selectedItem.xtream_id ?? selectedItem.id)
350→            );
351→
352→            if (!stillExists) {
353→                this.clearLiveSelection();
354→            }
355→        });
356→
357→        effect(() => {
358→            if (this.isGlobal || this.isLiveCategory()) {
359→                return;
360→            }
361→
362→            this.clearLiveSelection();
363→        });
364→
365→        if (this.isGlobal) {
366→            this.loadGlobalItems();
367→        } else if (this.currentPlaylist()) {
368→            this.xtreamStore.loadRecentItems(this.currentPlaylist);
369→        }
370→    }
371→
372→    private async loadGlobalItems() {
373→        try {
374→            await this.xtreamStore.loadGlobalRecentItems();
375→        } catch (error) {
376→            this.logger.error('Error loading global items', error);
377→        }
378→    }
379→
380→    clearHistory() {
381→        if (this.isGlobal) {
382→            this.xtreamStore.clearGlobalRecentlyViewed();
383→        } else {
384→            this.xtreamStore.clearRecentItems(this.xtreamStore.currentPlaylist);
385→        }
386→    }
387→
388→    openItem(item: FavoriteLayoutItem) {
389→        if (!isXtreamRecentViewItem(item)) {
390→            return;
391→        }
392→
393→        const source = item.source ?? 'xtream';
394→
395→        if ((source === 'stalker' || source === 'm3u') && this.isGlobal) {
396→            this.dialogRef?.close();
397→            const navigation = getRecentItemNavigation({
398→                id: item.id,
399→                title: item.title,
400→                type: item.type,
401→                playlist_id: item.playlist_id,
402→                poster_url: item.poster_url ?? '',
403→                xtream_id: item.xtream_id,
404→                category_id: item.category_id ?? item.type,
405→                source,
406→                stalker_item: item.stalker_item,
407→                viewed_at: item.viewed_at ?? '',
408→            });
409→            void this.router.navigate(navigation.link, {
410→                state: navigation.state,
411→            });
412→            return;
413→        }
414→
415→        const type = item.type === 'movie' ? 'vod' : item.type;
416→        this.xtreamStore.setSelectedContentType(type);
417→
418→        if (!this.isGlobal && type === 'live') {
419→            this.setCategoryId('live');
420→            this.selectLiveItem({
421→                id: item.id,
422→                poster_url: item.poster_url,
423→                stream_icon: item.stream_icon,
424→                title: item.title,
425→                xtream_id: Number(item.xtream_id),
426→            });
427→            return;
428→        }
429→
430→        if (this.isGlobal) {
431→            this.dialogRef?.close();
432→            const navigation = buildXtreamNavigationTarget({
433→                playlistId: item.playlist_id,
434→                type: item.type,
435→                categoryId: item.category_id,
436→                itemId: item.xtream_id,
437→                title: item.title,
438→                imageUrl: item.poster_url,
439→            });
440→            void this.router.navigate(navigation.link, {
441→                state: navigation.state,
442→            });
443→        } else {
444→            const navigation = buildXtreamNavigationTarget({
445→                playlistId: item.playlist_id,
446→                type: item.type,
447→                categoryId: item.category_id,
448→                itemId: item.xtream_id,
449→                title: item.title,
450→                imageUrl: item.poster_url,
451→            });
452→            void this.router.navigate(navigation.link, {
453→                state: navigation.state,
454→            });
455→        }
456→    }
457→
458→    async onRemoveItem(item: FavoriteLayoutItem) {
459→        if (!isXtreamRecentViewItem(item)) {
460→            return;
461→        }
462→
463→        try {
464→            if (this.isGlobal) {
465→                if (item.source === 'stalker') {
466→                    await firstValueFrom(
467→                        this.playlistsService.removeFromPortalRecentlyViewed(
468→                            item.playlist_id,
469→                            item.id
470→                        )
471→                    );
472→                } else if (item.source === 'm3u') {
473→                    await firstValueFrom(
474→                        this.playlistsService.removeFromM3uRecentlyViewed(
475→                            item.playlist_id,
476→                            String(item.xtream_id ?? item.id)
477→                        )
478→                    );
479→                } else {
480→                    await this.dbService.removeRecentItem(
481→                        Number(item.id),
482→                        item.playlist_id
483→                    );
484→                }
485→                await this.loadGlobalItems();
486→                return;
487→            }
488→
489→            const playlist = this.currentPlaylist();
490→            if (!playlist) {
491→                return;
492→            }
493→
494→            this.xtreamStore.removeRecentItem({
495→                itemId: Number(item.id),
496→                playlistId: playlist.id,
497→            });
498→        } catch (error) {
499→            this.logger.error('Error removing recent item', error);
500→        }
501→    }
502→
503→    getGroupedItems() {
504→        const items = this.visibleRecentItems();
505→        if (!this.isGlobal) return { default: items };
506→        return groupItemsByPlaylistName(items);
507→    }
508→
509→    updateRecentSearchTerm(term: string) {
510→        this.recentSearchTerm.set(term);
511→    }
512→
513→    toggleGroupByPlaylist(value: boolean) {
514→        this._groupByPlaylist.set(value);
515→        localStorage.setItem(
516→            RecentlyViewedComponent.GROUP_BY_STORAGE_KEY,
517→            String(value)
518→        );
519→    }
520→
521→    toggleTypeFilter(type: 'live' | 'movie' | 'series', value: boolean) {
522→        const next = {
523→            ...this._typeFilters(),
524→            [type]: value,
525→        };
526→        this._typeFilters.set(next);
527→        localStorage.setItem(
528→            RecentlyViewedComponent.TYPE_FILTERS_STORAGE_KEY,
529→            JSON.stringify(next)
530→        );
531→    }
532→
533→    setCategoryId(categoryId: string): void {
534→        this.collectionContext.setCategoryId(categoryId);
535→    }
536→
537→    selectLiveItem(item: XtreamRecentLiveItem): void {
538→        this.xtreamStore.setSelectedContentType('live');
539→        this.selectedLiveItem.set(item);
540→        const streamUrl = this.xtreamStore.constructStreamUrl(item);
541→        this.liveStreamUrl.set(streamUrl);
542→
543→        if (this.isEmbeddedPlayer()) {
544→            return;
545→        }
546→
547→        this.xtreamStore.openPlayer(
548→            streamUrl,
549→            item.title,
550→            item.poster_url || item.stream_icon || null
551→        );
552→    }
553→
554→    setLiveChannelSortMode(mode: LiveChannelSortMode): void {
555→        this.liveChannelSortMode.set(mode);
556→        localStorage.setItem(XTREAM_RECENT_LIVE_SORT_STORAGE_KEY, mode);
557→    }
558→
559→    private clearLiveSelection(): void {
560→        this.selectedLiveItem.set(null);
561→        this.liveStreamUrl.set('');
562→        this.xtreamStore.clearEpg();
563→        this.xtreamStore.setSelectedItem(null);
564→    }
565→}
