 546→        document.addEventListener('keydown', this.onDocumentKeydown);
 547→
 548→        this.router.events
 549→            .pipe(
 550→                filter(
 551→                    (event): event is NavigationEnd =>
 552→                        event instanceof NavigationEnd
 553→                ),
 554→                takeUntilDestroyed(this.destroyRef)
 555→            )
 556→            .subscribe((event) => {
 557→                this.currentUrl.set(event.urlAfterRedirects);
 558→                this.syncSearchFromRoute();
 559→            });
 560→
 561→        this.syncSearchFromRoute();
 562→
 563→        effect(() => {
 564→            const context = this.currentContext();
 565→            const section = this.currentSection();
 566→            const term = this.appliedSearchQuery();
 567→
 568→            if (!context || context.provider !== 'xtreams') {
