 571→
 572→            if (section === 'search') {
 573→                this.xtreamStore.setSearchTerm(term);
 574→                return;
 575→            }
 576→
 577→            if (section === 'vod' || section === 'series') {
 578→                this.xtreamStore.setCategorySearchTerm(term);
 579→            }
 580→        });
 581→
 582→        effect(() => {
 583→            const context = this.currentContext();
 584→            const section = this.currentSection();
 585→            const term = this.appliedSearchQuery();
 586→
 587→            if (
 588→                context?.provider !== 'stalker' ||
 589→                !section ||
 590→                (section !== 'vod' &&
 591→                    section !== 'series' &&
 592→                    section !== 'itv')
 593→            ) {
 594→                return;
 595→            }
 596→
 597→            this.stalkerStore.setSearchPhrase(term);
 598→        });
 599→
 600→        effect(() => {
 601→            if (!this.currentRoute().usesQuerySearch) {
 602→                return;
