 904→    private syncSearchQueryParam(term: string): void {
 905→        const nextTerm = term.trim();
 906→        const currentTerm = this.getRouteQueryParam('q');
 907→        if (nextTerm === currentTerm) {
 908→            return;
 909→        }
 910→
 911→        const routePath = this.currentUrl().split('?')[0];
 912→        const queryParams = {
 913→            ...this.router.parseUrl(this.currentUrl()).queryParams,
 914→        };
 915→
 916→        if (nextTerm.length > 0) {
 917→            queryParams['q'] = nextTerm;
 918→        } else {
 919→            delete queryParams['q'];
 920→        }
 921→
 922→        const queryString = this.toQueryString(queryParams);
 923→        const nextUrl = queryString ? `${routePath}?${queryString}` : routePath;
 924→        void this.router.navigateByUrl(nextUrl, { replaceUrl: true });
 925→    }
