 927→    private getRouteQueryParam(name: string): string {
 928→        const value = this.router.parseUrl(this.currentUrl()).queryParams[name];
 929→        return typeof value === 'string' ? value : '';
 930→    }
 931→
 932→    private toQueryString(queryParams: Record<string, unknown>): string {
 933→        const urlSearchParams = new URLSearchParams();
 934→
 935→        Object.entries(queryParams).forEach(([key, value]) => {
 936→            if (value == null) {
 937→                return;
 938→            }
 939→
 940→            if (Array.isArray(value)) {
 941→                value.forEach((item) =>
 942→                    urlSearchParams.append(key, String(item))
 943→                );
 944→                return;
 945→            }
 946→
 947→            urlSearchParams.set(key, String(value));
 948→        });
 949→
 950→        return urlSearchParams.toString();
 951→    }
