 953→    private bumpRefreshQueryParam(): void {
 954→        const routePath = this.currentUrl().split('?')[0];
 955→        const queryParams = {
 956→            ...this.router.parseUrl(this.currentUrl()).queryParams,
 957→            refresh: Date.now().toString(),
 958→        };
 959→
 960→        const queryString = this.toQueryString(queryParams);
 961→        const nextUrl = queryString ? `${routePath}?${queryString}` : routePath;
 962→        void this.router.navigateByUrl(nextUrl, { replaceUrl: true });
 963→    }
