  1→import {
  2→    ChangeDetectionStrategy,
  3→    Component,
  4→    computed,
  5→    effect,
  6→    inject,
  7→    input,
  8→    OnInit,
  9→    signal,
 10→} from '@angular/core';
 11→import { MatButtonToggleModule } from '@angular/material/button-toggle';
 12→import { MatIconModule } from '@angular/material/icon';
 13→import { ActivatedRoute } from '@angular/router';
 14→import { TranslatePipe } from '@ngx-translate/core';
 15→import {
 16→    CollectionContentType,
 17→    CollectionScope,
 18→    isWorkspaceLayoutRoute,
 19→    queryParamSignal,
 20→    ScopeToggleService,
 21→    UnifiedCollectionItem,
 22→    UnifiedFavoritesDataService,
 23→    UnifiedRecentDataService,
 24→} from '@iptvnator/portal/shared/util';
 25→import { UnifiedLiveTabComponent } from './unified-live-tab.component';
 26→import { UnifiedGridTabComponent } from './unified-grid-tab.component';
 27→
 28→@Component({
 29→    selector: 'app-unified-collection-page',
 30→    templateUrl: './unified-collection-page.component.html',
 31→    styleUrl: './unified-collection-page.component.scss',
 32→    changeDetection: ChangeDetectionStrategy.OnPush,
 33→    imports: [
 34→        MatButtonToggleModule,
 35→        MatIconModule,
 36→        TranslatePipe,
 37→        UnifiedGridTabComponent,
 38→        UnifiedLiveTabComponent,
 39→    ],
 40→})
 41→export class UnifiedCollectionPageComponent implements OnInit {
 42→    readonly mode = input<'favorites' | 'recent'>('favorites');
 43→    readonly portalType = input<string>();
 44→    readonly defaultScope = input<CollectionScope>();
 45→
 46→    private readonly route = inject(ActivatedRoute);
 47→    private readonly scopeService = inject(ScopeToggleService);
 48→    private readonly favoritesData = inject(UnifiedFavoritesDataService);
 49→    private readonly recentData = inject(UnifiedRecentDataService);
 50→    readonly isWorkspaceLayout = isWorkspaceLayoutRoute(this.route);
 51→    private readonly routeSearchTerm = queryParamSignal(
 52→        this.route,
 53→        'q',
 54→        (value) => (value ?? '').trim()
 55→    );
 56→    readonly workspaceSearchTerm = computed(() =>
 57→        this.isWorkspaceLayout ? this.routeSearchTerm() : ''
 58→    );
 59→
 60→    readonly isLoading = signal(true);
 61→    readonly allItems = signal<UnifiedCollectionItem[]>([]);
 62→    readonly selectedContentType = signal<CollectionContentType>('live');
 63→
 64→    readonly skeletonRows = Array.from({ length: 12 }, (_, i) => i);
 65→    readonly skeletonCards = Array.from({ length: 8 }, (_, i) => i);
 66→
 67→    readonly playlistId = computed(() => {
 68→        let current = this.route.snapshot;
 69→        while (current) {
 70→            if (current.params['id']) {
 71→                return current.params['id'] as string;
 72→            }
 73→            current = current.parent!;
 74→        }
 75→        return undefined;
 76→    });
 77→
 78→    readonly scopeKey = computed(() => this.mode());
 79→    readonly scope = signal<CollectionScope>('playlist');
 80→
 81→    readonly liveItems = computed(() =>
 82→        this.allItems().filter((i) => i.contentType === 'live')
 83→    );
 84→    readonly movieItems = computed(() =>
 85→        this.allItems().filter((i) => i.contentType === 'movie')
 86→    );
 87→    readonly seriesItems = computed(() =>
 88→        this.allItems().filter((i) => i.contentType === 'series')
 89→    );
 90→
 91→    readonly hasLive = computed(() => this.liveItems().length > 0);
 92→    readonly hasMovies = computed(() => this.movieItems().length > 0);
 93→    readonly hasSeries = computed(() => this.seriesItems().length > 0);
 94→
 95→    readonly availableTypes = computed(() => {
 96→        const types: CollectionContentType[] = [];
 97→        if (this.hasLive()) types.push('live');
 98→        if (this.hasMovies()) types.push('movie');
 99→        if (this.hasSeries()) types.push('series');
100→        return types;
101→    });
102→
103→    readonly showContentToggle = computed(
104→        () => this.availableTypes().length > 1
105→    );
106→
107→    readonly title = computed(() => {
108→        return this.mode() === 'favorites'
109→            ? 'PORTALS.FAVORITES'
110→            : 'PORTALS.RECENTLY_VIEWED';
111→    });
112→
113→    constructor() {
114→        effect(() => {
115→            this.scope();
116→            this.loadData();
117→        });
118→    }
119→
120→    ngOnInit(): void {
121→        const queryScope = this.route.snapshot.queryParams['scope'] as
122→            | CollectionScope
123→            | undefined;
124→        if (queryScope === 'all' || queryScope === 'playlist') {
125→            this.scope.set(queryScope);
126→        } else if (this.defaultScope()) {
127→            this.scope.set(this.defaultScope()!);
128→        } else {
129→            const persisted = this.scopeService.getScope(this.scopeKey());
130→            this.scope.set(persisted());
131→        }
132→    }
133→
134→    onScopeChange(value: CollectionScope): void {
135→        this.scope.set(value);
136→        this.scopeService.setScope(this.scopeKey(), value);
137→    }
138→
139→    onContentTypeChange(value: CollectionContentType): void {
140→        this.selectedContentType.set(value);
141→    }
142→
143→    async onRemoveItem(item: UnifiedCollectionItem): Promise<void> {
144→        if (this.mode() === 'favorites') {
145→            await this.favoritesData.removeFavorite(item);
146→        } else {
147→            await this.recentData.removeRecentItem(item);
148→        }
149→        this.allItems.update((items) =>
150→            items.filter((i) => i.uid !== item.uid)
151→        );
152→    }
153→
154→    async onReorder(items: UnifiedCollectionItem[]): Promise<void> {
155→        const nonLive = this.allItems().filter(
156→            (i) => i.contentType !== 'live'
157→        );
158→        this.allItems.set([...items, ...nonLive]);
159→        await this.favoritesData.reorder(items);
160→    }
161→
162→    private async loadData(): Promise<void> {
163→        this.isLoading.set(true);
164→        try {
165→            const s = this.scope();
166→            const pid = this.playlistId();
167→            const pt = this.portalType();
168→            const items =
169→                this.mode() === 'favorites'
170→                    ? await this.favoritesData.getFavorites(s, pid, pt)
171→                    : await this.recentData.getRecentItems(s, pid, pt);
172→            this.allItems.set(items);
173→            this.autoSelectContentType();
174→        } catch {
175→            this.allItems.set([]);
176→        } finally {
177→            this.isLoading.set(false);
178→        }
179→    }
180→
181→    private autoSelectContentType(): void {
182→        const types = this.availableTypes();
183→        if (types.length > 0 && !types.includes(this.selectedContentType())) {
184→            this.selectedContentType.set(types[0]);
185→        }
186→    }
187→}
