  1→import { inject, Injectable } from '@angular/core';
  2→import { Store } from '@ngrx/store';
  3→import { selectAllPlaylistsMeta } from 'm3u-state';
  4→import { firstValueFrom, map } from 'rxjs';
  5→import { DatabaseService, PlaylistsService } from 'services';
  6→import {
  7→    buildPlaylistRecentItems,
  8→    Playlist,
  9→    PlaylistMeta,
 10→} from 'shared-interfaces';
 11→import {
 12→    buildCollectionUid,
 13→    UnifiedCollectionItem,
 14→} from './unified-collection-item.interface';
 15→import { CollectionScope } from './scope-toggle.service';
 16→import { xtreamContentType } from './collection-helpers';
 17→
 18→@Injectable({ providedIn: 'root' })
 19→export class UnifiedRecentDataService {
 20→    private readonly store = inject(Store);
 21→    private readonly dbService = inject(DatabaseService);
 22→    private readonly playlistsService = inject(PlaylistsService);
 23→
 24→    async getRecentItems(
 25→        scope: CollectionScope,
 26→        playlistId?: string,
 27→        portalType?: string
 28→    ): Promise<UnifiedCollectionItem[]> {
 29→        if (scope === 'playlist' && playlistId) {
 30→            return this.getPlaylistRecentItems(playlistId, portalType);
 31→        }
 32→        return this.getAllRecentItems();
 33→    }
 34→
 35→    async removeRecentItem(item: UnifiedCollectionItem): Promise<void> {
 36→        if (item.sourceType === 'xtream' && item.contentId != null) {
 37→            await this.dbService.removeRecentItem(
 38→                item.contentId,
 39→                item.playlistId
 40→            );
 41→        } else if (item.sourceType === 'stalker' || item.sourceType === 'm3u') {
 42→            const sourceItemId = item.uid.split('::')[2];
 43→            await firstValueFrom(
 44→                this.playlistsService.removeFromPortalRecentlyViewed(
 45→                    item.playlistId,
 46→                    sourceItemId
 47→                )
 48→            );
 49→        }
 50→    }
 51→
 52→    async clearRecentItems(
 53→        scope: CollectionScope,
 54→        playlistId?: string
 55→    ): Promise<void> {
 56→        if (scope === 'playlist' && playlistId) {
 57→            await this.dbService.clearPlaylistRecentItems(playlistId);
 58→            await firstValueFrom(
 59→                this.playlistsService.clearPlaylistRecentlyViewed(playlistId)
 60→            );
 61→        } else {
 62→            await this.dbService.clearGlobalRecentlyViewed();
 63→            const playlists = (await firstValueFrom(
 64→                this.playlistsService.getAllPlaylists()
 65→            )) as Playlist[];
 66→            await Promise.all(
 67→                playlists
 68→                    .filter((p) => Boolean(p.macAddress) || !p.serverUrl)
 69→                    .map((p) =>
 70→                        firstValueFrom(
 71→                            this.playlistsService.clearPlaylistRecentlyViewed(p._id)
 72→                        )
 73→                    )
 74→            );
 75→        }
 76→    }
 77→
 78→    // ─── Private ──────────────────────────────────────
 79→
 80→    private async getAllRecentItems(): Promise<UnifiedCollectionItem[]> {
 81→        const [xtream, playlistBased] = await Promise.all([
 82→            this.getXtreamGlobalRecent(),
 83→            this.getPlaylistBasedRecent(),
 84→        ]);
 85→        return [...xtream, ...playlistBased].sort(
 86→            (a, b) =>
 87→                new Date(b.viewedAt ?? 0).getTime() -
 88→                new Date(a.viewedAt ?? 0).getTime()
 89→        );
 90→    }
 91→
 92→    private async getPlaylistRecentItems(
 93→        playlistId: string,
 94→        portalType?: string
 95→    ): Promise<UnifiedCollectionItem[]> {
 96→        if (portalType === 'xtream') {
 97→            return this.getXtreamPlaylistRecent(playlistId);
 98→        }
 99→        if (portalType === 'stalker') {
100→            return this.getStalkerPlaylistRecent(playlistId);
101→        }
102→        return this.getM3uPlaylistRecent(playlistId);
103→    }
104→
105→    private async getXtreamGlobalRecent(): Promise<UnifiedCollectionItem[]> {
106→        try {
107→            const rows = await this.dbService.getGlobalRecentlyViewed();
108→            return (rows || []).map((row) => ({
109→                uid: buildCollectionUid('xtream', row.playlist_id, row.xtream_id),
110→                name: row.title,
111→                contentType: xtreamContentType(row.type),
112→                sourceType: 'xtream' as const,
113→                playlistId: row.playlist_id,
114→                playlistName: row.playlist_name ?? 'Xtream',
115→                logo: row.type === 'live' ? (row.poster_url ?? null) : null,
116→                posterUrl: row.type !== 'live' ? (row.poster_url ?? null) : null,
117→                xtreamId: row.xtream_id,
118→                categoryId: row.category_id,
119→                tvgId: row.type === 'live' ? String(row.xtream_id) : undefined,
120→                contentId: row.id,
121→                viewedAt: row.viewed_at,
122→            }));
123→        } catch {
124→            return [];
125→        }
126→    }
127→
128→    private async getXtreamPlaylistRecent(
129→        playlistId: string
130→    ): Promise<UnifiedCollectionItem[]> {
131→        try {
132→            const rows = await this.dbService.getRecentItems(playlistId);
133→            const meta = await this.getPlaylistMeta(playlistId);
134→            return (rows || []).map((row) => ({
135→                uid: buildCollectionUid('xtream', playlistId, row.xtream_id),
136→                name: row.title,
137→                contentType: xtreamContentType(row.type),
138→                sourceType: 'xtream' as const,
139→                playlistId,
140→                playlistName: meta?.title || 'Xtream',
141→                logo: row.type === 'live' ? (row.poster_url ?? null) : null,
142→                posterUrl: row.type !== 'live' ? (row.poster_url ?? null) : null,
143→                xtreamId: row.xtream_id,
144→                categoryId: row.category_id,
145→                tvgId: row.type === 'live' ? String(row.xtream_id) : undefined,
146→                contentId: row.id,
147→                viewedAt: row.viewed_at ?? '',
148→            }));
149→        } catch {
150→            return [];
151→        }
152→    }
153→
154→    private async getPlaylistBasedRecent(): Promise<UnifiedCollectionItem[]> {
155→        const playlists = (await firstValueFrom(
156→            this.playlistsService.getAllPlaylists()
157→        )) as Playlist[];
158→        const items = buildPlaylistRecentItems(playlists, {
159→            stalker: 'Stalker Portal',
160→            m3u: 'M3U',
161→        });
162→        return items.map((item) => ({
163→            uid: buildCollectionUid(
164→                (item.source as 'm3u' | 'stalker') ?? 'm3u',
165→                item.playlist_id,
166→                item.id
167→            ),
168→            name: item.title,
169→            contentType: xtreamContentType(item.type),
170→            sourceType: (item.source as 'm3u' | 'stalker') ?? 'm3u',
171→            playlistId: item.playlist_id,
172→            playlistName: item.playlist_name ?? '',
173→            logo: item.type === 'live' ? (item.poster_url ?? null) : null,
174→            posterUrl: item.type !== 'live' ? (item.poster_url ?? null) : null,
175→            stalkerItem: item.stalker_item,
176→            viewedAt: item.viewed_at,
177→        }));
178→    }
179→
180→    private async getStalkerPlaylistRecent(
181→        playlistId: string
182→    ): Promise<UnifiedCollectionItem[]> {
183→        const all = await this.getPlaylistBasedRecent();
184→        return all.filter(
185→            (i) => i.sourceType === 'stalker' && i.playlistId === playlistId
186→        );
187→    }
188→
189→    private async getM3uPlaylistRecent(
190→        playlistId: string
191→    ): Promise<UnifiedCollectionItem[]> {
192→        const all = await this.getPlaylistBasedRecent();
193→        return all.filter(
194→            (i) => i.sourceType === 'm3u' && i.playlistId === playlistId
